SELECT MAX(points) AS max_points
FROM players_stats
WHERE sport_id = 0;

SELECT AVG(points) AS average_points
FROM players_stats
WHERE sport_id = 1;

SELECT player_id, SUM(points) AS total_points
FROM players_stats
GROUP BY player_id;

SELECT player_id, COUNT(*) AS games_played
FROM players_games
GROUP BY player_id;
